private flush(contentType: string, body: string): void {
  if (!this.headers.has('content-type')) {
    this.headers.set('content-type', contentType);
  }
  this.writeHead();
  this.res.end(body);
}

private flushBytes(contentType: string, body: Buffer): void {
  if (!this.headers.has('content-type')) {
    this.headers.set('content-type', contentType);
  }
  // Pin a numeric Content-Length so HTTP/1.1 pipelining works without
  // chunked-transfer overhead. Buffer.length is the byte length.
  this.headers.set('content-length', body.length.toString());
  this.writeHead();
  this.res.end(body);
}

private flushEmpty(): void {
  this.writeHead();
  this.res.end();
}

private writeHead(): void {
  const headersOut: Record<string, string | string[]> = {};
  for (const [k, v] of this.headers) headersOut[k] = v;
  if (this.setCookies.length > 0) {
    headersOut['set-cookie'] = this.setCookies;
  }
  this.res.writeHead(this.statusCode, headersOut);

