1	import { createHmac, timingSafeEqual } from 'node:crypto';
2	import { PluginError } from '@ax/core';
3	
4	const PLUGIN_NAME = '@ax/http-server';
5	const KEY_LEN = 32;
6	// HMAC-SHA256 -> 32 bytes -> base64url is 43 chars (no padding).
7	const HMAC_B64URL_LEN = 43;
8	// RFC 6265 says servers MAY accept >= 4096-byte values. We cap at 4 KiB
9	// of pre-encoded plaintext so a runaway caller can't fill cookie storage.
10	const MAX_COOKIE_VALUE_BYTES = 4 * 1024;
11	
12	export interface SignedCookieOptions {
13	  maxAge?: number;
14	  expires?: Date;
15	  path?: string;
16	  domain?: string;
17	  /** Override Secure derivation. When omitted, derived from request protocol. */
18	  secure?: boolean;
19	  sameSite?: 'Lax' | 'Strict' | 'None';
20	}
21	
22	export interface CookieEnv {
23	  /** True iff the underlying connection / proxy chain is HTTPS. */
24	  isSecureRequest: boolean;
25	}
26	
27	/**
28	 * Parse a 32-byte signing key from an env-var string. Accepts 64 hex chars
29	 * OR 44 base64 chars. Mirrors @ax/credentials/src/crypto.ts parseKeyFromEnv,
30	 * intentionally reimplemented inline to honor invariant I2 (no cross-plugin
31	 * imports).
32	 */
33	export function parseCookieKey(raw: string): Buffer {
34	  if (/^[0-9a-fA-F]{64}$/.test(raw)) {
35	    return Buffer.from(raw, 'hex');
36	  }
37	  const b64 = Buffer.from(raw, 'base64');
38	  if (b64.length === KEY_LEN) return b64;
39	  throw new PluginError({
40	    code: 'invalid-cookie-key',
41	    plugin: PLUGIN_NAME,
42	    message:
43	      'AX_HTTP_COOKIE_KEY must be a 32-byte key (64 hex chars or 44 base64 chars)',
44	  });
45	}
46	
47	export function assertKeyLength(key: Buffer): void {
48	  if (key.length !== KEY_LEN) {
49	    throw new PluginError({
50	      code: 'invalid-cookie-key',
51	      plugin: PLUGIN_NAME,
52	      message: `cookie signing key must be ${KEY_LEN} bytes; got ${key.length}`,
53	    });
54	  }
55	}
56	
57	function b64urlEncode(buf: Buffer): string {
58	  return buf.toString('base64url');
59	}
60	
61	function b64urlDecode(s: string): Buffer | null {
62	  // Reject anything that has b64 padding or non-url-safe chars; base64url
63	  // is strict here and silent decoding can mask tamper attempts.
64	  if (!/^[A-Za-z0-9_-]*$/.test(s)) return null;
65	  try {
66	    return Buffer.from(s, 'base64url');
67	  } catch {
68	    return null;
69	  }
70	}
71	
72	function computeHmac(key: Buffer, payload: Buffer): Buffer {
73	  return createHmac('sha256', key).update(payload).digest();
74	}
75	
76	/**
77	 * Sign `value` with `key` and return the cookie-safe wire form
78	 * `<base64url(value)>.<base64url(hmac)>`. Throws if value exceeds
79	 * MAX_COOKIE_VALUE_BYTES (pre-encoding).
80	 */
81	export function signCookieValue(key: Buffer, value: string): string {
82	  assertKeyLength(key);
83	  const payload = Buffer.from(value, 'utf8');
84	  if (payload.length > MAX_COOKIE_VALUE_BYTES) {
85	    throw new PluginError({
86	      code: 'invalid-payload',
87	      plugin: PLUGIN_NAME,
88	      message: `signed cookie value exceeds ${MAX_COOKIE_VALUE_BYTES}-byte cap`,
89	    });
90	  }
91	  const sig = computeHmac(key, payload);
92	  return `${b64urlEncode(payload)}.${b64urlEncode(sig)}`;
93	}
94	
95	/**
96	 * Verify `wire` against `key`. Returns the recovered plaintext string on
97	 * success, or null on any tamper (length mismatch, malformed segments,
98	 * HMAC mismatch). Never throws.
99	 */
100	export function verifyCookieValue(key: Buffer, wire: string): string | null {
101	  assertKeyLength(key);
102	  if (typeof wire !== 'string' || wire.length === 0) return null;
103	  // Use lastIndexOf so any '.' inside a base64url payload (none, but
